export const meta = {
  name: 'post-fix-verification-audit',
  description: 'Post-fix audit to verify all issues were resolved and find any remaining problems',
  phases: [
    { title: 'Backend Verification', detail: 'Verify backend fixes are working' },
    { title: 'Frontend Verification', detail: 'Verify frontend fixes are working' },
    { title: 'Mobile Verification', detail: 'Verify mobile configuration fixes' },
    { title: 'Integration Testing', detail: 'Verify API integrations work end-to-end' },
    { title: 'Final Report', detail: 'Compile verification results' }
  ],
};


const PROJECT_ROOT = 'C:\\Users\\user\\OneDrive\\Desktop\\rez-v5\\Homeservice';

// Phase 1: Backend Verification
phase('Backend Verification');
const backendVerification = await parallel([
  () => agent(`Verify Backend API fixes at ${PROJECT_ROOT}/backend

Check if these issues were fixed:
1. admin.routes.ts - realtime-metrics endpoint now returns real data or proper error
2. admin.routes.ts - getWithdrawalDetails is now exported from controller
3. admin.routes.ts - searchProviders is now implemented
4. admin.controller.ts - NYC coordinates changed to UAE/Dubai
5. admin.controller.ts - Stripe secret key throws error if missing
6. admin.routes.ts - test/create-provider endpoint removed or protected
7. invoice.routes.ts - transformation properly converts lineItems to items
8. coupon.routes.ts - Joi validation added
9. wallet.routes.ts - validation for withdrawal limits added

Return JSON: {fixed: [], not_fixed: [], new_issues: []}`, {phase: 'Backend Verification', label: 'verify-backend'}),
]);


// Phase 2: Frontend Verification
phase('Frontend Verification');
const frontendVerification = await parallel([
  () => agent(`Verify Data Format Fixes at ${PROJECT_ROOT}/frontend/src

Check if these issues were fixed:
1. provider/ServiceAvailabilityPage.tsx - Bundle endpoint corrected
2. provider/MyBundlesPage.tsx - /providers/my/services endpoint fixed
3. customerDashboardApi.ts - API response structure normalized
4. provider/ProviderEarningsPage.tsx - Transaction type mapping has fallback
5. invoice transformation - properly maps lineItems → items
6. providerInsightsApi.ts - Period parameters normalized
7. notification types - normalized between frontend and backend
8. AdminDashboard.tsx - Stats response shape handled correctly

Return JSON: {fixed: [], not_fixed: [], new_issues: []}`, {phase: 'Frontend Verification', label: 'verify-data-formats'}),

  () => agent(`Verify Error Handling Improvements at ${PROJECT_ROOT}/frontend/src

Check if these issues were fixed:
1. SearchPage.tsx - PageErrorBoundary added
2. WalletPage.tsx - PageErrorBoundary added
3. ProfilePage.tsx - PageErrorBoundary added
4. InsightsDashboard.tsx - Error boundaries for sub-components
5. Admin pages - Error boundaries added
6. Console.error replaced with toast notifications
7. Socket operations - proper error handling
8. Retry logic added for critical API calls
9. Race condition handling in Promise.allSettled improved

Return JSON: {fixed: [], not_fixed: [], new_issues: []}`, {phase: 'Frontend Verification', label: 'verify-error-handling'}),
]);


// Phase 3: Mobile Verification
phase('Mobile Verification');
const mobileVerification = await agent(`Verify Mobile Build Fixes at ${PROJECT_ROOT}/frontend

Check if these issues were fixed:
1. config/api.ts - localhost fallback removed/replaced with proper env var
2. services/api.ts - localhost fallback fixed
3. services/socket.ts - localhost fallback fixed
4. android/app/build.gradle - google-services.json handling improved
5. android/variables.gradle - SDK version changed to 34
6. android/gradle.properties - Jetifier and memory settings added
7. AndroidManifest.xml - Deep link verification handled
8. ios/Info.plist - Camera, location, photo permissions added
9. ios/Info.plist - Background modes added
10. package.json - Mobile build scripts added
11. PWA manifest.json - Icons verified

Return JSON: {fixed: [], not_fixed: [], new_issues: []}`, {phase: 'Mobile Verification', label: 'verify-mobile'});


// Phase 4: Integration Testing
phase('Integration Testing');
const integrationTesting = await agent(`Verify Integration Points at ${PROJECT_ROOT}

Check if these integrations work:
1. Provider dashboard → Backend API (service endpoints)
2. Provider dashboard → Backend API (availability endpoints)
3. Provider dashboard → Backend API (insights endpoints)
4. Admin dashboard → Backend API (stats endpoints)
5. Customer dashboard → Backend API (bookings endpoints)
6. Bundle endpoints exist and return correct data format
7. All protected routes have proper authentication checks
8. All protected routes have proper role checks

Verify:
- Endpoints are exported from controllers
- Response formats match frontend expectations
- Field names are consistent

Return JSON: {working: [], broken: [], needs_attention: []}`, {phase: 'Integration Testing', label: 'verify-integration'});


// Phase 5: Final Report
phase('Final Report');
const allResults = {
  backend: backendVerification.flat(),
  frontend: frontendVerification.flat(),
  mobile: mobileVerification,
  integration: integrationTesting
};

const totalFixed = 
  (allResults.backend.filter(r => r.status === 'fixed').length || 0) +
  (allResults.frontend?.flat?.()?.filter(r => r.status === 'fixed').length || 0) +
  (allResults.mobile?.fixed?.length || 0) +
  (allResults.integration?.working?.length || 0);

const remainingIssues = 
  (allResults.backend.filter(r => r.status === 'not_fixed').length || 0) +
  (allResults.frontend?.flat?.()?.filter(r => r.status === 'not_fixed').length || 0) +
  (allResults.mobile?.not_fixed?.length || 0) +
  (allResults.integration?.broken?.length || 0);

const newIssues = 
  (allResults.backend.filter(r => r.status === 'new_issue').length || 0) +
  (allResults.frontend?.flat?.()?.filter(r => r.status === 'new_issue').length || 0) +
  (allResults.mobile?.new_issues?.length || 0);


return {
  summary: {
    totalFixed,
    remainingIssues,
    newIssues
  },
  results: allResults
};
